package entity_test

import (
	"testing"

	"github.com/nikita-rulenko/heisenbug-portal/internal/entity"
)

func TestUnitBench89C1CE8C(t *testing.T) {
	tests := []struct {
		name     string
		items    []entity.OrderItem
		expected float64
	}{
		{
			name:     "empty items slice",
			items:    []entity.OrderItem{},
			expected: 0,
		},
		{
			name: "nil items slice",
			items: nil,
			expected: 0,
		},
		{
			name: "item with zero quantity",
			items: []entity.OrderItem{
				{Quantity: 0, Price: 10.0},
			},
			expected: 0,
		},
		{
			name: "item with negative price",
			items: []entity.OrderItem{
				{Quantity: 5, Price: -10.0},
			},
			expected: -50.0,
		},
		{
			name: "very large quantity",
			items: []entity.OrderItem{
				{Quantity: 1_000_000, Price: 0.01},
			},
			expected: 10000.0,
		},
		{
			name: "mixed positive, zero, and negative values",
			items: []entity.OrderItem{
				{Quantity: 2, Price: 10.0},   // 20
				{Quantity: 0, Price: 100.0},  // 0
				{Quantity: 3, Price: -5.0},   // -15
			},
			expected: 5.0,
		},
	}

	for _, tt := range tests {
		tt := tt // capture range variable
		t.Run(tt.name, func(t *testing.T) {
			order := entity.Order{
				Items: tt.items,
			}
			order.CalculateTotal()
			if order.Total != tt.expected {
				t.Fatalf("expected total %.2f, got %.2f", tt.expected, order.Total)
			}
		})
	}
}

