package entity_test

import (
	"testing"

	"github.com/nikita-rulenko/heisenbug-portal/internal/entity"
)

func TestUnitBench3C9C1438(t *testing.T) {
	tests := []struct {
		name   string
		status entity.OrderStatus
		want   bool
	}{
		{name: "new", status: entity.OrderStatusNew, want: true},
		{name: "processing", status: entity.OrderStatusProcessing, want: true},
		{name: "completed", status: entity.OrderStatusCompleted, want: false},
		{name: "cancelled", status: entity.OrderStatusCancelled, want: false},
		{name: "empty", status: entity.OrderStatus(""), want: false},
		{name: "unknown", status: entity.OrderStatus("unknown"), want: false},
	}

	for _, tt := range tests {
		tt := tt
		t.Run(tt.name, func(t *testing.T) {
			t.Parallel()
			o := entity.Order{Status: tt.status}
			if got := o.CanCancel(); got != tt.want {
				t.Fatalf("Order.CanCancel() = %v, want %v (status=%v)", got, tt.want, tt.status)
			}
		})
	}
}

