package entity_test

// CHOICE: Order.Validate — testing whitespace CustomerID edge case not covered
import (
	"testing"

	"github.com/nikita-rulenko/heisenbug-portal/internal/entity"
)

func TestUnitBench42523BE0(t *testing.T) {
	tests := []struct {
		name        string
		order       entity.Order
		wantErr     error
	}{
		{
			name: "valid order",
			order: entity.Order{
				CustomerID: "alice",
				Items: []entity.OrderItem{
					{ProductID: 1, Quantity: 2, Price: 5.0},
				},
			},
			wantErr: nil,
		},
		{
			name: "whitespace CustomerID should be accepted",
			order: entity.Order{
				CustomerID: "   ",
				Items: []entity.OrderItem{
					{ProductID: 2, Quantity: 1, Price: 3.5},
				},
			},
			wantErr: nil,
		},
		{
			name: "empty CustomerID returns ErrEmptyCustomerID",
			order: entity.Order{
				CustomerID: "",
				Items: []entity.OrderItem{
					{ProductID: 3, Quantity: 1, Price: 2.0},
				},
			},
			wantErr: entity.ErrEmptyCustomerID,
		},
		{
			name: "empty CustomerID with invalid item still returns ErrEmptyCustomerID (priority)",
			order: entity.Order{
				CustomerID: "",
				Items: []entity.OrderItem{
					{ProductID: 0, Quantity: 0, Price: 0},
				},
			},
			wantErr: entity.ErrEmptyCustomerID,
		},
	}

	for _, tt := range tests {
		tt := tt // capture range variable
		t.Run(tt.name, func(t *testing.T) {
			err := tt.order.Validate()
			if tt.wantErr != nil {
				if err == nil {
					t.Fatalf("expected error %v, got nil", tt.wantErr)
				}
				if err != tt.wantErr {
					t.Fatalf("expected error %v, got %v", tt.wantErr, err)
				}
			} else {
				if err != nil {
					t.Fatalf("expected no error, got %v", err)
				}
			}
		})
	}
}
